// src/App.js
import React from 'react';
import { Routes, Route } from 'react-router-dom';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import StudentLandingPage from './pages/StudentLanding'; // Example page
import ProfessorLandingPage from './pages/ProfessorLanding'; // Example page
import SecretaryLandingPage from './pages/SecretaryLanding'; // Example page
import AdminLandingPage from './pages/AdminLandingPage'; // Example page

const App = () => {
  return (
    <Routes>
      <Route path="/" element={<LoginPage />} />
      <Route path="/register" element={<RegisterPage />} />
      <Route path="/student-landing" element={<StudentLandingPage />} />
      <Route path="/professor-landing" element={<ProfessorLandingPage />} />
      <Route path="/secretary-landing" element={<SecretaryLandingPage />} />
      <Route path="/admin-landing" element={<AdminLandingPage />} />
    </Routes>
  );
};

export default App;
